// Import route registration functions after mocks
import { registerDemandRoutes } from '../../server/api/demands';
import { registerBuildingRoutes } from '../../server/api/buildings';
import { registerBillRoutes } from '../../server/api/bills';
import { registerDocumentRoutes } from '../../server/api/documents';
import { registerUserRoutes } from '../../server/api/users';

describe('Form Submission Tests', () => {
  let app: express.Application;
  let agent: ReturnType<typeof request.agent>;

  const testOrg = {
    id: '00000000-0000-0000-0000-000000000001',
    name: 'Test Organization',
    type: 'condo_association',
    isActive: true,
  };

  const testBuilding = {
    id: '00000000-0000-0000-0000-000000000002',
    name: 'Test Building',
    address: '456 Form Street',
    city: 'Montreal',
    province: 'QC',
    postalCode: 'H1B 1B1',
    buildingType: 'condo',
    organizationId: testOrg.id,
    totalUnits: 100,
    isActive: true,
  };

  const testResidence = {
    id: '00000000-0000-0000-0000-000000000003',
    unitNumber: '101',
    buildingId: testBuilding.id,
    floor: 1,
    isActive: true,
  };

  const testUser = {
    id: '00000000-0000-0000-0000-000000000004',
    email: 'formtest@example.com',
    username: 'formtester',
    password: 'hashed-password',
    firstName: 'Form',
    lastName: 'Tester',
    role: 'admin' as const,
    language: 'en' as const,
    isActive: true,
  };

  beforeEach(() => {
    // Reset all mocks
    jest.clearAllMocks();

    // Create fresh Express app for each test
    app = express();
    app.use(express.json());

    // Setup session middleware
    app.use(session({
      secret: 'test-secret',
      resave: false,
      saveUninitialized: false,
      cookie: { secure: false },
    }));

    // Configure auth middleware to inject test user
    mockAuthMiddleware.mockImplementation((req: any, res: any, next: any) => {
      req.user = {
        id: testUser.id,
        username: testUser.username,
        email: testUser.email,
        firstName: testUser.firstName,
        lastName: testUser.lastName,
        role: testUser.role,
        isActive: testUser.isActive,
        organizations: [testOrg.id],
      } as AuthenticatedUser;
      next();
    });

    // Set up default database mocks
    const defaultSelectMock = {
      from: jest.fn().mockReturnValue({
        where: jest.fn().mockReturnValue({
          limit: jest.fn().mockResolvedValue([]),
          orderBy: jest.fn().mockResolvedValue([]),
        }),
        innerJoin: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([]),
        }),
        leftJoin: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([]),
        }),
      }),
    };

    const defaultUpdateMock = {
      set: jest.fn().mockReturnValue({
        where: jest.fn().mockResolvedValue(undefined),
      }),
    };

    const defaultInsertMock = {
      values: jest.fn().mockReturnValue({
        returning: jest.fn().mockResolvedValue([]),
      }),
    };

    const defaultDeleteMock = {
      where: jest.fn().mockResolvedValue(undefined),
    };

    (mockDb.select as any).mockReturnValue(defaultSelectMock);
    (mockDb.update as any).mockReturnValue(defaultUpdateMock);
    (mockDb.insert as any).mockReturnValue(defaultInsertMock);
    (mockDb.delete as any).mockReturnValue(defaultDeleteMock);

    // Register all routes
    registerDemandRoutes(app);
    registerBuildingRoutes(app);
    registerBillRoutes(app);
    registerDocumentRoutes(app);
    registerUserRoutes(app);

    agent = request.agent(app);
  });

  describe('Demand Creation Form', () => {
    it('should successfully submit demand with all required fields', async () => {
      const demandData = {
        type: 'maintenance',
        description: 'Test maintenance request for form submission testing',
        buildingId: testBuilding.id,
        residenceId: testResidence.id,
      };

      const mockCreatedDemand = {
        id: 'demand-1',
        ...demandData,
        submitterId: testUser.id,
        status: 'submitted',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      // Mock the insert operation
      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDemand]),
        }),
      });

      // Mock user organization check for managers
      (mockDb.select as any).mockReturnValue({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([{ organizationId: testOrg.id }]),
          innerJoin: jest.fn().mockReturnValue({
            where: jest.fn().mockResolvedValue([testBuilding]),
          }),
        }),
      });

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBe(201);
      expect(response.body).toBeDefined();
      expect(response.body.id).toBe('demand-1');
      expect(response.body.type).toBe('maintenance');
      expect(response.body.description).toBe(demandData.description);
      expect(response.body.submitterId).toBe(testUser.id);
      expect(response.body.buildingId).toBe(testBuilding.id);
      expect(response.body.status).toBe('submitted');
    });

    it('should auto-populate buildingId and residenceId if not provided', async () => {
      const demandData = {
        type: 'complaint',
        description: 'Test complaint without explicit IDs',
      };

      const mockCreatedDemand = {
        id: 'demand-2',
        ...demandData,
        buildingId: testBuilding.id,
        residenceId: testResidence.id,
        submitterId: testUser.id,
        status: 'submitted',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      // Mock user residence lookup for auto-population
      (mockDb.select as any).mockReturnValue({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([{
            residenceId: testResidence.id,
            buildingId: testBuilding.id,
          }]),
          innerJoin: jest.fn().mockReturnValue({
            where: jest.fn().mockResolvedValue([{
              residenceId: testResidence.id,
              buildingId: testBuilding.id,
            }]),
          }),
        }),
      });

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDemand]),
        }),
      });

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBe(201);
      expect(response.body.buildingId).toBe(testBuilding.id);
      expect(response.body.residenceId).toBe(testResidence.id);
    });

    it('should handle optional UUID fields correctly', async () => {
      const demandData = {
        type: 'information',
        description: 'Test with optional assignation fields',
        buildingId: testBuilding.id,
        residenceId: testResidence.id,
        assignationBuildingId: testBuilding.id,
        assignationResidenceId: testResidence.id,
      };

      const mockCreatedDemand = {
        id: 'demand-3',
        ...demandData,
        submitterId: testUser.id,
        status: 'submitted',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDemand]),
        }),
      });

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBe(201);
      expect(response.body.assignationBuildingId).toBe(testBuilding.id);
      expect(response.body.assignationResidenceId).toBe(testResidence.id);
    });

    it('should validate required fields and return appropriate errors', async () => {
      const invalidDemandData = {
        type: 'maintenance',
        // Missing description
      };

      const response = await agent
        .post('/api/demands')
        .send(invalidDemandData);

      expect(response.status).toBeGreaterThanOrEqual(400);
      expect(response.body).toHaveProperty('message');
    });

    it('should handle empty string UUIDs correctly', async () => {
      const demandData = {
        type: 'other',
        description: 'Test with empty string UUIDs',
        buildingId: testBuilding.id,
        residenceId: testResidence.id,
        assignationBuildingId: '',
        assignationResidenceId: '',
      };

      const mockCreatedDemand = {
        id: 'demand-4',
        type: demandData.type,
        description: demandData.description,
        buildingId: testBuilding.id,
        residenceId: testResidence.id,
        assignationBuildingId: null,
        assignationResidenceId: null,
        submitterId: testUser.id,
        status: 'submitted',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDemand]),
        }),
      });

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBe(201);
      expect(response.body.assignationBuildingId).toBeFalsy();
      expect(response.body.assignationResidenceId).toBeFalsy();
    });
  });

  describe('Building Form Submission', () => {
    it('should successfully create building with all required fields', async () => {
      const buildingData = {
        name: 'New Test Building',
        organizationId: testOrg.id,
        address: '789 Building Street',
        city: 'Montreal',
        province: 'QC',
        postalCode: 'H1C 1C1',
        buildingType: 'condo',
      };

      const mockCreatedBuilding = {
        id: 'building-1',
        ...buildingData,
        isActive: true,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      // Mock residences count check
      (mockDb.select as any).mockReturnValue({
        from: jest.fn().mockReturnValue({
          where: jest.fn().mockResolvedValue([{ count: 0 }]),
        }),
      });

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedBuilding]),
        }),
      });

      const response = await agent
        .post('/api/admin/buildings')
        .send(buildingData);

      expect(response.status).toBe(201);
      expect(response.body).toHaveProperty('id');
      expect(response.body.name).toBe(buildingData.name);
      expect(response.body.organizationId).toBe(buildingData.organizationId);
    });

    it('should validate organization ID is required', async () => {
      const buildingData = {
        name: 'Building Without Org',
        address: '999 No Org Street',
        city: 'Montreal',
        province: 'QC',
        postalCode: 'H1D 1D1',
        buildingType: 'condo',
        // Missing organizationId
      };

      const response = await agent
        .post('/api/admin/buildings')
        .send(buildingData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });

    it('should handle invalid organization ID', async () => {
      const buildingData = {
        name: 'Building Invalid Org',
        organizationId: 'invalid-uuid',
        address: '888 Invalid Street',
        city: 'Montreal',
        province: 'QC',
        postalCode: 'H1E 1E1',
        buildingType: 'condo',
      };

      const response = await agent
        .post('/api/admin/buildings')
        .send(buildingData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });
  });

  describe('Bill Creation Form', () => {
    it('should successfully create bill with all required fields', async () => {
      const billData = {
        title: 'Test Monthly Bill',
        description: 'Test bill for form submission',
        category: 'utilities',
        vendor: 'Test Utility Company',
        paymentType: 'recurrent',
        schedulePayment: 'monthly',
        totalAmount: '150.75',
        startDate: '2025-01-01',
        status: 'draft',
        buildingId: testBuilding.id,
      };

      const mockCreatedBill = {
        id: 'bill-1',
        billNumber: 'BILL-001',
        ...billData,
        totalAmount: 150.75,
        createdBy: testUser.id,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedBill]),
        }),
      });

      const response = await agent
        .post('/api/bills')
        .send(billData);

      expect(response.status).toBe(201);
      expect(response.body).toHaveProperty('id');
      expect(response.body.title).toBe(billData.title);
      expect(response.body.buildingId).toBe(billData.buildingId);
    });

    it('should validate required amount field', async () => {
      const billData = {
        title: 'Bill Without Amount',
        category: 'maintenance',
        paymentType: 'unique',
        startDate: '2025-01-01',
        status: 'draft',
        buildingId: testBuilding.id,
        // Missing totalAmount
      };

      const response = await agent
        .post('/api/bills')
        .send(billData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });

    it('should handle optional schedule payment for unique bills', async () => {
      const billData = {
        title: 'One-time Bill',
        category: 'repairs',
        paymentType: 'unique',
        totalAmount: '500.00',
        startDate: '2025-01-01',
        status: 'draft',
        buildingId: testBuilding.id,
      };

      const mockCreatedBill = {
        id: 'bill-2',
        billNumber: 'BILL-002',
        ...billData,
        totalAmount: 500.00,
        createdBy: testUser.id,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedBill]),
        }),
      });

      const response = await agent
        .post('/api/bills')
        .send(billData);

      expect(response.status).toBe(201);
      expect(response.body.paymentType).toBe('unique');
    });
  });

  describe('Document Upload Form', () => {
    it('should validate document creation with building ID', async () => {
      const documentData = {
        name: 'Test Document',
        type: 'maintenance',
        dateReference: '2025-01-01',
        isVisibleToTenants: true,
        buildingId: testBuilding.id,
      };

      const mockCreatedDocument = {
        id: 'document-1',
        ...documentData,
        uploadedBy: testUser.id,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDocument]),
        }),
      });

      const response = await agent
        .post('/api/documents')
        .send(documentData);

      expect([200, 201]).toContain(response.status);
      if (response.status === 201) {
        expect(response.body).toHaveProperty('id');
        expect(response.body.name).toBe(documentData.name);
      }
    });

    it('should validate document creation with residence ID', async () => {
      const documentData = {
        name: 'Residence Document',
        type: 'lease',
        dateReference: '2025-01-01',
        isVisibleToTenants: false,
        residenceId: testResidence.id,
      };

      const mockCreatedDocument = {
        id: 'document-2',
        ...documentData,
        uploadedBy: testUser.id,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedDocument]),
        }),
      });

      const response = await agent
        .post('/api/documents')
        .send(documentData);

      expect([200, 201]).toContain(response.status);
      if (response.status === 201) {
        expect(response.body).toHaveProperty('id');
        expect(response.body.residenceId).toBe(testResidence.id);
      }
    });
  });

  describe('User Invitation Form', () => {
    it('should create invitation with proper validation', async () => {
      const invitationData = {
        email: 'newuser@example.com',
        role: 'resident',
        organizationId: testOrg.id,
        buildingId: testBuilding.id,
      };

      const mockCreatedInvitation = {
        id: 'invitation-1',
        ...invitationData,
        token: 'test-token-123',
        status: 'pending',
        expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
        createdBy: testUser.id,
        createdAt: new Date(),
      };

      (mockDb.insert as any).mockReturnValue({
        values: jest.fn().mockReturnValue({
          returning: jest.fn().mockResolvedValue([mockCreatedInvitation]),
        }),
      });

      const response = await agent
        .post('/api/invitations')
        .send(invitationData);

      expect([200, 201]).toContain(response.status);
      if (response.status === 201) {
        expect(response.body).toHaveProperty('token');
        expect(response.body.email).toBe(invitationData.email);
      }
    });

    it('should validate email format', async () => {
      const invitationData = {
        email: 'invalid-email',
        role: 'resident',
        organizationId: testOrg.id,
      };

      const response = await agent
        .post('/api/invitations')
        .send(invitationData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });
  });

  describe('Form Error Handling', () => {
    it('should handle malformed UUID fields', async () => {
      const demandData = {
        type: 'maintenance',
        description: 'Test with malformed UUID',
        buildingId: 'not-a-uuid',
        residenceId: 'also-not-a-uuid',
      };

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });

    it('should handle null values in required fields', async () => {
      const demandData = {
        type: null,
        description: null,
        buildingId: testBuilding.id,
      };

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });

    it('should handle very long field values', async () => {
      const demandData = {
        type: 'maintenance',
        description: 'x'.repeat(5000),
        buildingId: testBuilding.id,
      };

      const response = await agent
        .post('/api/demands')
        .send(demandData);

      expect(response.status).toBeGreaterThanOrEqual(400);
    });
  });
});
